import React, { useState } from 'react';
import { ngoApi } from '../../../services/api';

export default function RegisterNGO() {
  const [userCert, setUserCert] = useState('');
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);
  const [ngos, setNgos] = useState([]);

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);
    setNgos([]);
    try {
      const res = await ngoApi.getAllNGOs({ userCert });
      // backend may return data in res.data or directly in res
      const data = res?.data ?? res;
      if (!data || (Array.isArray(data) && data.length === 0)) {
        setMessage('No NGOs found for this UserCert.');
      } else {
        setNgos(Array.isArray(data) ? data : [data]);
      }
    } catch (err) {
      setMessage(err?.response?.data?.error || err.message || 'Failed to fetch NGOs');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 900, margin: '0 auto' }}>
      <form onSubmit={onSubmit} style={{ marginBottom: 20 }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={userCert}
            onChange={(e) => setUserCert(e.target.value)}
            placeholder="Enter userCert to fetch associated NGOs"
            style={{ width: '100%' }}
            required
          />
        </div>

        <button type="submit" disabled={loading} style={{ marginTop: 12 }}>
          {loading ? 'Fetching...' : 'Fetch NGOs'}
        </button>
      </form>

      {message && <div style={{ marginBottom: 12 }}>{String(message)}</div>}

      {ngos.length > 0 && (
        <div>
          <h3>NGOs associated with UserCert</h3>
          <table style={{ width: '100%', borderCollapse: 'collapse' }}>
            <thead>
              <tr>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>NGO ID</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Name</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Reg No</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Address</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Contact</th>
                <th style={{ textAlign: 'left', borderBottom: '1px solid #ddd' }}>Description</th>
              </tr>
            </thead>
            <tbody>
              {ngos.map((ngo, idx) => (
                <tr key={ngo.ngoId ?? idx}>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.ngoId || ngo.id}</td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.name}</td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.regNo}</td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.address}</td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.contact}</td>
                  <td style={{ padding: '8px 4px', borderBottom: '1px solid #f0f0f0' }}>{ngo.description}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
